; Engagement metrics are calculated based on the number of views and replies for each post and user; 
; The overall rank is determined by the sum of view and reply counts; 
; Tertiles are used to divide the data into four equal groups based on views and replies; 
; This query can be used to identify the most engaging content and users in a discussion forum.

sql:
SELECT category_id, name, description, COUNT(*) AS post_count
FROM categories
GROUP BY category_id, name, description;

SELECT post_id, COUNT(reply_id) AS reply_count
FROM replies
GROUP BY post_id;
